var e=e=>{let t=document.createElement(`div`);return t.classList.add(`p-5`,`shadow-md`,`bg-white`,`mt-4`),t.innerHTML=`<h2 class="text-xl font-bold">${e.title}</h2>
   <p class="mt-2 text-sm">
   ${e.description}
   </p>
   <a href="${e.link}" class="text-blue-700 text-sm mt-2 block">View project</a>`,t};export{e as t};